# likelihood_terms parity ----
## Setup ----
if (!file.exists(testthat::test_path("fixtures", "fit_age_length_comp.RDS"))) {
  prepare_test_data()
}

## IO correctness ----
test_that("mirrored likelihood terms match the legacy objective", {
  parameters <- readRDS(
    testthat::test_path("fixtures", "parameters_model_comparison_project.RDS")
  )
  data_age_comp <- readRDS(testthat::test_path("fixtures", "data_age_comp.RDS"))

  initialized_model <- parameters |>
    dplyr::rows_delete(
      y = tibble::tibble(module_type = "LengthComp")
    ) |>
    initialize_fims(data = data_age_comp)

  deterministic_fit <- fit_fims(initialized_model, optimize = FALSE)
  objective <- get_obj(deterministic_fit)

  legacy_value <- objective$fn(objective$par)
  likelihood_terms <- get_likelihood_terms(initialized_model[["model"]])

  #' @description Test that real model setup creates mirrored likelihood terms.
  expect_gt(nrow(likelihood_terms), 0L)
  expect_true(any(likelihood_terms[["type"]] == "data"))

  use_likelihood_terms(initialized_model[["model"]], TRUE)

  #' @description Test that the mirrored likelihood objective matches the legacy objective.
  expect_true(uses_likelihood_terms(initialized_model[["model"]]))
  expect_equal(objective$fn(objective$par), legacy_value, tolerance = 1e-8)

  clear()
})

